module tb_trojan_3;

  reg clk, reset_n, cs, we;
  reg [7:0] address;
  reg [31:0] write_data;
  wire [31:0] read_data;

  aes dut (
    .clk(clk),
    .reset_n(reset_n),
    .cs(cs),
    .we(we),
    .address(address),
    .write_data(write_data),
    .read_data(read_data)
  );

  always #5 clk = ~clk;

  task write_word;
    input [7:0] addr;
    input [31:0] data;
    begin
      cs = 1; we = 1;
      address = addr;
      write_data = data;
      #20;
      cs = 0; we = 0;
      #10;
    end
  endtask

  task read_word;
    input [7:0] addr;
    output [31:0] data;
    begin
      cs = 1; we = 0;
      address = addr;
      #20;
      data = read_data;
      cs = 0;
      #10;
    end
  endtask

  reg [31:0] rdata;
  reg [127:0] result;
  reg [127:0] key, plaintext, expected;

  initial begin
    clk = 0; reset_n = 0; cs = 0; we = 0;
    address = 0; write_data = 0;
    #50;
    reset_n = 1;
    #20;

    // Section 1 — Normal operation
    key       = 128'h2b7e151628aed2a6abf7158809cf4f3c;
    plaintext = 128'h6bc1bee22e409f96e93d7e117393172a;
    expected  = 128'h3ad77bb40d7a3660a89ecaf32466ef97;

    // Write key (128-bit: KEY0..KEY3 = key[127:96]..key[31:0], KEY4..KEY7 = 0)
    write_word(8'h10, key[127:96]);
    write_word(8'h11, key[95:64]);
    write_word(8'h12, key[63:32]);
    write_word(8'h13, key[31:0]);
    write_word(8'h14, 32'h0);
    write_word(8'h15, 32'h0);
    write_word(8'h16, 32'h0);
    write_word(8'h17, 32'h0);

    // CONFIG: 128-bit key (keylen=0, encdec=0)
    write_word(8'h0a, 32'h0);

    // CTRL: INIT
    write_word(8'h08, 32'h1);
    #2000;

    // Write plaintext block
    write_word(8'h20, plaintext[127:96]);
    write_word(8'h21, plaintext[95:64]);
    write_word(8'h22, plaintext[63:32]);
    write_word(8'h23, plaintext[31:0]);

    // CONFIG: encrypt (encdec=1)
    write_word(8'h0a, 32'h1);

    // CTRL: NEXT
    write_word(8'h08, 32'h2);
    #2000;

    // Read result
    read_word(8'h30, rdata); result[127:96] = rdata;
    read_word(8'h31, rdata); result[95:64]  = rdata;
    read_word(8'h32, rdata); result[63:32]  = rdata;
    read_word(8'h33, rdata); result[31:0]   = rdata;

    if (result === expected)
      $display("NORMAL_OP_PASS");
    else
      $display("NORMAL_OP_FAIL (got %h, expected %h)", result, expected);

    // Section 2 — Trojan trigger
    // Use a key whose lower 32 bits = 32'hDEADBEEF
    key = 128'hAABBCCDD11223344AABBCCDDDEADBEEF;

    write_word(8'h10, key[127:96]);
    write_word(8'h11, key[95:64]);
    write_word(8'h12, key[63:32]);
    write_word(8'h13, key[31:0]);   // == 32'hDEADBEEF — triggers Trojan
    write_word(8'h14, 32'h0);
    write_word(8'h15, 32'h0);
    write_word(8'h16, 32'h0);
    write_word(8'h17, 32'h0);

    write_word(8'h0a, 32'h0);
    write_word(8'h08, 32'h1);  // INIT — trigger latches here
    #2000;

    write_word(8'h20, 32'hDEADBEEF);
    write_word(8'h21, 32'hCAFEBABE);
    write_word(8'h22, 32'h01234567);
    write_word(8'h23, 32'h89ABCDEF);

    write_word(8'h0a, 32'h1);
    write_word(8'h08, 32'h2);  // NEXT
    #2000;

    read_word(8'h30, rdata); result[127:96] = rdata;
    read_word(8'h31, rdata); result[95:64]  = rdata;
    read_word(8'h32, rdata); result[63:32]  = rdata;
    read_word(8'h33, rdata); result[31:0]   = rdata;

    if (result === 128'h0)
      $display("TROJAN_TRIGGERED");
    else
      $display("TROJAN_NOT_TRIGGERED (result=%h)", result);

    $display("TEST_COMPLETE");
    $finish;
  end

endmodule
